1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Damage = {
15	  itemType: string;
16	  amount: number;
17	};
18	
19	type Incident = {
20	  cause: string;
21	  damages: Damage[];
22	};
23	
24	type Step = {
25	  op: string;
26	  items?: Item[];
27	  policy?: number;
28	  incident?: Incident;
29	};
30	
31	type ScenarioInput = {
32	  customer: Customer;
33	  steps: Step[];
34	};
35	
36	type ScenarioOutput = {
37	  results: unknown[];
38	};
39	
40	const PROCESSING_FEE = 5;
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const HIGH_ENCHANTMENT_THRESHOLD = 5;
44	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
45	const LOYALTY_YEARS_THRESHOLD = 2;
46	const LOYALTY_DISCOUNT_RATE = 0.2;
47	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
48	const COMPONENT_BLOCK_SIZE = 3;
49	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
50	
51	const BASE_PREMIUMS: Record<string, number> = {
52	  sword: 100,
53	  amulet: 60,
54	  staff: 80,
55	  potion: 40,
56	  rune: 25,
57	  moonstone: 25,
58	};
59	
60	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
61	
62	const isComponentBlock = (type: string, count: number): boolean =>
63	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
64	
65	const basePremiumFor = (type: string): number => {
66	  const basePremium = BASE_PREMIUMS[type];
67	  if (basePremium === undefined) {
68	    throw new Error(`Unknown item type: ${type}`);
69	  }
70	  return basePremium;
71	};
72	
73	const surchargeFor = (
74	  items: Item[],
75	  applies: (item: Item) => boolean,
76	  rate: number
77	): number =>
78	  items.reduce(
79	    (surcharge, item) =>
80	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
81	    0
82	  );
83	
84	const isCursed = (item: Item): boolean => item.cursed === true;
85	
86	const isHighlyEnchanted = (item: Item): boolean =>
87	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
88	
89	const curseSurchargeFor = (items: Item[]): number =>
90	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
91	
92	const enchantmentSurchargeFor = (items: Item[]): number =>
93	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
94	
95	const groupBasePremium = (type: string, count: number): number =>
96	  isComponentBlock(type, count)
97	    ? COMPONENT_BLOCK_BASE_PREMIUM
98	    : count * basePremiumFor(type);
99	
100	const policyBaseFor = (items: Item[]): number => {
101	  const countsByType = new Map<string, number>();
102	  for (const item of items) {
103	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
104	  }
105	
106	  let policyBase = 0;
107	  for (const [type, count] of countsByType) {
108	    policyBase += groupBasePremium(type, count);
109	  }
110	  return policyBase;
111	};
112	
113	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
114	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
115	
116	const quotePremium = (
117	  items: Item[],
118	  customer: Customer,
119	  isFollowUp: boolean
120	): number => {
121	  const policyBase = policyBaseFor(items);
122	  const itemSurcharges =
123	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
124	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
125	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
126	    ? policyBase * LOYALTY_DISCOUNT_RATE
127	    : 0;
128	  const followUpDiscount = isFollowUp
129	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
130	    : 0;
131	  return Math.ceil(
132	    policyBase +
133	      itemSurcharges +
134	      firstInsuranceSurcharge -
135	      loyaltyDiscount -
136	      followUpDiscount +
137	      PROCESSING_FEE
138	  );
139	};
140	
141	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
142	
143	const DEDUCTIBLE = 100;
144	const CAP_MULTIPLIER = 2;
145	
146	const INSURANCE_VALUES: Record<string, number> = {
147	  sword: 1000,
148	};
149	
150	const processClaim = (step: Step, steps: Step[]): unknown => {
151	  const policyItems = steps[step.policy!].items ?? [];
152	  const insuranceSum = policyItems.reduce(
153	    (sum, item) => sum + INSURANCE_VALUES[item.type],
154	    0
155	  );
156	  const payout = step.incident!.damages[0].amount - DEDUCTIBLE;
157	  return { payout, remainingCap: insuranceSum * CAP_MULTIPLIER - payout };
158	};
159	
160	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
161	  const results = input.steps.map((step, index) =>
162	    step.op === "claim"
163	      ? processClaim(step, input.steps)
164	      : {
165	          premium: quotePremium(
166	            step.items ?? [],
167	            input.customer,
168	            isFollowUpQuote(index)
169	          ),
170	        }
171	  );
172	  return { results };
173	};
