const insuranceSumFor = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);

const processClaim = (step: Step, steps: Step[]): unknown => {
  const policyItems = steps[step.policy!].items ?? [];
  const payoutCap = insuranceSumFor(policyItems) * CAP_MULTIPLIER;
  const payout = step.incident!.damages[0].amount - DEDUCTIBLE;
  return { payout, remainingCap: payoutCap - payout };
};
